// portal-a24-historico-reservas — validar_firma_ts_rol.
// Lee el raw body desde BINARIO ('data'); recomputa HMAC-SHA256 sobre los bytes EXACTOS
// (D-C-29). Revalida ts (300s), rol (allowlist del wrapper, D-C-39), action binding
// (D-C-41) y -A24- el payload de filtros (2da defensa; el smoke directo pega aca sin gateway).
const crypto = require('crypto');

// Secreto: SOLO desde Variables de n8n ($vars.VITA_HMAC_SECRET). En Modo B (n8n Cloud SIN
// Variables) se PEGA el secreto real reemplazando el placeholder. El template commiteado queda
// sanitizado; el secreto vive solo en el nodo de la instancia.
const SECRET = (typeof $vars !== 'undefined' && $vars && $vars.VITA_HMAC_SECRET)
  ? $vars.VITA_HMAC_SECRET
  : '__PEGAR_SECRETO_O_USAR_VARIABLE__';

// Assert duro POR PREFIJO (L-C-10): sobrevive al find-replace del placeholder completo.
if (!SECRET || SECRET.startsWith('__PEGAR_')) {
  throw new Error('VITA_HMAC_SECRET no configurado en n8n Variables; abortando (assert duro).');
}

const item = $input.first();
const wh = item.json;

// Helper de salida de rechazo (mantiene shape con payload_norm:null).
function rej(motivo, b) {
  return [{ json: { ok_firma: false, motivo,
    ambiente_esperado: (b && b.ambiente_esperado) ?? null,
    rol: (b && b.rol) ?? null, action: (b && b.action) ?? null,
    ts: (b && b.ts) ?? null, payload_norm: null } }];
}

// 1) Raw body como Buffer EXACTO. Prioridad: binario 'data'. Fallback: wh.rawBody (L-C-05).
let buf = null;
try {
  if (item.binary && item.binary.data) {
    buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  }
} catch (e) {
  buf = null;
}
if (!buf) {
  const rawField = wh.rawBody;
  if (Buffer.isBuffer(rawField)) buf = rawField;
  else if (rawField && rawField.type === 'Buffer' && Array.isArray(rawField.data)) buf = Buffer.from(rawField.data);
  else if (typeof rawField === 'string') buf = Buffer.from(rawField, 'utf8');
}
if (!buf) return rej('raw_body_ausente', null);

// 2) Firma recibida en el header.
const headers = wh.headers || {};
const sigHeader = headers['x-vita-signature'] || headers['X-Vita-Signature'] || '';

// 3) HMAC recomputado sobre los MISMOS bytes.
const expected = 'sha256=' + crypto.createHmac('sha256', SECRET).update(buf).digest('hex');

// 4) Comparacion timing-safe (requiere igual longitud).
let firmaOk = false;
try {
  const a = Buffer.from(sigHeader);
  const b = Buffer.from(expected);
  firmaOk = a.length === b.length && crypto.timingSafeEqual(a, b);
} catch (e) {
  firmaOk = false;
}
if (!firmaOk) return rej('firma_invalida', null);

// 5) Parseo (firma ya validada sobre bytes crudos).
let body;
try {
  body = JSON.parse(buf.toString('utf8'));
} catch (e) {
  return rej('payload_invalido', null);
}

// 6) Ventana de ts (anti-replay liviano, D-C-29): |now - ts| <= 300s.
const ts = Number(body.ts);
if (!Number.isFinite(ts) || Math.abs(Date.now() - ts) > 300000) {
  return rej('ts_fuera_de_ventana', { ...body, ts: body.ts });
}
body.ts = ts;

// 7) Allowlist de rol del wrapper (D-C-39, 2da defensa). A24 = vicky/socio (sin jenny, D-C-03/11).
const ROLES_OK = ['vicky', 'socio'];
if (!ROLES_OK.includes(body.rol)) return rej('rol_no_permitido', body);

// 8) Action binding (D-C-41): EXPECTED_ACTION = historico.reservas (A24).
const EXPECTED_ACTION = 'historico.reservas';
if (body.action !== EXPECTED_ACTION) return rej('accion_desconocida', body);

// 9) Payload de A24 (filtros opcionales). Reject-unknown + normalizacion. Espejo del futuro
//    payloadHistoricoReservas del gateway. Floor 2026-07-01 (D-C-11/20) clampea fecha_desde
//    (data layer del SQL ademas lo impone con GREATEST: floor no negociable).
const FLOOR = '2026-07-01';
const ESTADOS_OK = ['confirmada', 'activa', 'completada', 'cancelada', 'cancelada_con_cargo', 'conflicto_pendiente'];
const PERMITIDAS = ['fecha_desde', 'fecha_hasta', 'id_cabana', 'estado', 'texto', 'limit', 'offset'];
const MAXLEN = 1000;

// payload: ausente/null -> {}; objeto plano -> se usa; cualquier otra cosa (string, array,
// numero, bool) -> payload_invalido (no se coerciona silenciosamente a {}).
let pl = {};
if (body.payload === undefined || body.payload === null) {
  pl = {};
} else if (typeof body.payload === 'object' && !Array.isArray(body.payload)) {
  pl = body.payload;
} else {
  return rej('payload_invalido', body);
}
for (const k of Object.keys(pl)) {
  if (!PERMITIDAS.includes(k)) return rej('payload_invalido', body);
}

function isYMD(s) {
  if (typeof s !== 'string' || !/^\d{4}-\d{2}-\d{2}$/.test(s)) return false;
  const Y = +s.slice(0, 4), M = +s.slice(5, 7), D = +s.slice(8, 10);
  if (M < 1 || M > 12 || D < 1 || D > 31) return false;
  const dt = new Date(Date.UTC(Y, M - 1, D));
  return dt.getUTCFullYear() === Y && dt.getUTCMonth() === M - 1 && dt.getUTCDate() === D;
}

// fecha_desde: opcional; YMD valida; clamp al floor (nunca < floor). Default = floor.
let fecha_desde = FLOOR;
if (pl.fecha_desde !== undefined && pl.fecha_desde !== null) {
  if (!isYMD(pl.fecha_desde)) return rej('payload_invalido', body);
  fecha_desde = (pl.fecha_desde < FLOOR) ? FLOOR : pl.fecha_desde;
}

// fecha_hasta: opcional; YMD valida y >= fecha_desde; default null (sin cota: buscador operativo).
let fecha_hasta = null;
if (pl.fecha_hasta !== undefined && pl.fecha_hasta !== null) {
  if (!isYMD(pl.fecha_hasta)) return rej('payload_invalido', body);
  if (pl.fecha_hasta < fecha_desde) return rej('payload_invalido', body);
  fecha_hasta = pl.fecha_hasta;
}

// id_cabana: opcional; entero > 0; default null = todas (sin sentinela externa).
let id_cabana = null;
if (pl.id_cabana !== undefined && pl.id_cabana !== null) {
  if (typeof pl.id_cabana !== 'number' || !Number.isSafeInteger(pl.id_cabana) || pl.id_cabana <= 0) return rej('payload_invalido', body);
  id_cabana = pl.id_cabana;
}

// estado: opcional; en el enum estado_reserva_enum; default null = todos.
let estado = null;
if (pl.estado !== undefined && pl.estado !== null) {
  if (typeof pl.estado !== 'string' || !ESTADOS_OK.includes(pl.estado)) return rej('payload_invalido', body);
  estado = pl.estado;
}

// texto: opcional; string no vacio <= 1000 (ILIKE sobre nombre/apellido/telefono/email). Default null.
let texto = null;
if (pl.texto !== undefined && pl.texto !== null) {
  if (typeof pl.texto !== 'string' || pl.texto.length > MAXLEN) return rej('payload_invalido', body);
  const t = pl.texto.trim();
  if (t !== '') texto = t;
}

// limit: opcional; entero; clamp [1,200]; default 50.
let limit = 50;
if (pl.limit !== undefined && pl.limit !== null) {
  if (typeof pl.limit !== 'number' || !Number.isSafeInteger(pl.limit)) return rej('payload_invalido', body);
  limit = Math.min(Math.max(pl.limit, 1), 200);
}

// offset: opcional; entero >= 0; default 0.
let offset = 0;
if (pl.offset !== undefined && pl.offset !== null) {
  if (typeof pl.offset !== 'number' || !Number.isSafeInteger(pl.offset) || pl.offset < 0) return rej('payload_invalido', body);
  offset = pl.offset;
}

const payload_norm = { fecha_desde, fecha_hasta, id_cabana, estado, texto, limit, offset };

return [{ json: { ok_firma: true, motivo: null,
  ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null,
  action: body.action ?? null, ts, payload_norm } }];

// portal-a24-historico-reservas — verificar_acceso. Compara ambiente y arma el envelope de
// rechazo (D-C-18/35). En exito marca {ok:true} para habilitar el IF; el envelope final de
// exito lo arma el render.
const v = $('validar_firma_ts_rol').first().json;
const ambItem = $('leer_ambiente').first();
const real = (ambItem && ambItem.json) ? (ambItem.json.valor ?? null) : null;

function envErr(code, message, detail) {
  return [{ json: { ok: false, error: { code, message, detail: detail ?? null } } }];
}

if (!v.ok_firma) {
  const msgs = {
    firma_invalida: 'firma HMAC invalida o ausente',
    ts_fuera_de_ventana: 'timestamp fuera de la ventana permitida (300s)',
    payload_invalido: 'payload invalido (filtro mal formado o clave no permitida)',
    raw_body_ausente: 'no llego el raw body (activa Raw Body en el Webhook)',
    rol_no_permitido: 'rol no habilitado para esta accion',
    accion_desconocida: 'accion no corresponde a este endpoint'
  };
  return envErr(v.motivo, msgs[v.motivo] || 'rechazado', null);
}

if (v.ambiente_esperado !== real) {
  return envErr('ambiente_incorrecto', 'el sobre no corresponde a este entorno', { esperado: v.ambiente_esperado, real });
}

return [{ json: { ok: true } }];

// ===== portal-a24-historico-reservas — render JSON lista paginada =====
// Buscador operativo de reservas desde el floor 2026-07-01 (D-C-11/20). Filtros ya aplicados
// en SQL. Contrato data:{filas, limit, offset, total}; montos NUMERICOS crudos. Privacidad
// (D-C-03): huesped nombre/telefono/email; SIN dni ni notas internas. Lista vacia => filas:[]
// con ok:true (D-C-47), NUNCA no_encontrado. saldo_real puede ser negativo (sobrecobro): se
// reporta tal cual. total = universo filtrado (COUNT(*) OVER, antes de LIMIT).
function safeAll(nodeName, keyField) {
  try {
    const items = $(nodeName).all();
    const failed = items.some(it => it && it.json && (it.json.error || it.error));
    if (failed) return { ok: false, rows: [] };
    const rows = items.map(it => it.json).filter(j => j && j[keyField] !== undefined && j[keyField] !== null);
    return { ok: true, rows };
  } catch (e) { return { ok: false, rows: [] }; }
}
function num(v) { if (v === null || v === undefined || v === '') return null; const n = Number(v); return Number.isFinite(n) ? n : null; }
function int0(v) { const n = Number(v); return Number.isFinite(n) ? Math.trunc(n) : 0; }

const r = safeAll('PG: leer historico', 'id_reserva');
if (!r.ok) {
  return [{ json: { ok: false, error: { code: 'error_interno', message: 'no se pudo cargar el historico', detail: null } } }];
}

const pn = $('validar_firma_ts_rol').first().json.payload_norm || {};
const limit  = int0(pn.limit);
const offset = int0(pn.offset);
const total  = r.rows.length > 0 ? int0(r.rows[0].total_filtrado) : 0;

const filas = r.rows.map(x => ({
  id_reserva: int0(x.id_reserva),
  id_cabana: int0(x.id_cabana),
  cabana: x.cabana,
  fecha_checkin: x.fecha_checkin,
  fecha_checkout: x.fecha_checkout,
  personas: x.personas,
  estado: x.estado,
  canal_origen: x.canal_origen,
  monto_total: num(x.monto_total),
  monto_sena: num(x.monto_sena),
  saldo_real: num(x.saldo_real),
  created_at: x.created_at,
  huesped: {
    nombre: x.huesped_nombre ?? null,
    telefono: x.huesped_telefono ?? null,
    email: x.huesped_email ?? null
  }
}));

return [{ json: { ok: true, data: { filas, limit, offset, total } } }];
